        Assert.assertTrue(InfHelper.greaterOrEqual("0.0", "-0"));
        Assert.assertTrue(InfHelper.greaterOrEqual("0", "0"));
        Assert.assertTrue(InfHelper.greaterOrEqual("0", "-0"));
        Assert.assertTrue(InfHelper.greaterOrEqual("0", "0.0"));
        Assert.assertTrue(InfHelper.greaterOrEqual("0", "-0.0"));
        Assert.assertTrue(InfHelper.greaterOrEqual(InfHelper.POSINF, InfHelper.POSINF));

        Assert.assertTrue(InfHelper.greaterOrEqual(InfHelper.POSINF, InfHelper.NEGINF));
        Assert.assertTrue(InfHelper.greaterOrEqual(InfHelper.POSINF, "0.0"));
        Assert.assertTrue(InfHelper.greaterOrEqual(InfHelper.POSINF, "-0.0"));
        Assert.assertTrue(InfHelper.greaterOrEqual(InfHelper.POSINF, "0"));
        Assert.assertTrue(InfHelper.greaterOrEqual(InfHelper.POSINF, "-0"));
