        Assert.assertFalse(InfHelper.greaterOrEqual("-0", InfHelper.POSINF));
        Assert.assertFalse(InfHelper.greaterOrEqual("0.0", InfHelper.POSINF));
        Assert.assertFalse(InfHelper.greaterOrEqual("-0.0", InfHelper.POSINF));
        Assert.assertFalse(InfHelper.greaterOrEqual(InfHelper.NEGINF, InfHelper.POSINF));

